class Solution:
    def minFlips(self, nums: list[int], mask: list[int], i: int) -> int:
        ans = 0
        for j in range(len(nums)):
            if mask[j] == 1 and i < j:
                ans += bin(nums[j]).count('1')
            elif mask[j] == 0 and i >= j:
                ans += bin(nums[j]).count('1')
        return ans

def main():
    nums = list(map(int, input().split()))
    mask = list(map(int, input().split()))
    i = int(input())
    ans = Solution().minFlips(nums, mask, i)
    print(ans)

if __name__ == '__main__':
    main()

